(() => {
    interface ICircularDeep {
      name: string;
      big: bigint;
      embedded: {hello: string; child?: ICircularDeep};
    }
    interface RootNotCircular {
      isRoot: true;
      ciChild: ICircularDeep;
    }
    return {build: () => createValidate<RootNotCircular>(), buildErrors: () => noErrs(createGetValidationErrors<RootNotCircular>())};
  })()

c(z.lazy(() => {
    const ciDeep: z.ZodType = z.object({
      name: z.string(),
      big: z.bigint(),
      embedded: z.object({hello: z.string(), child: z.lazy(() => ciDeep).optional()}),
    });
    return z.object({isRoot: z.literal(true), ciChild: ciDeep});
  }))

c(
    Type.Object({
      isRoot: Type.Literal(true),
      ciChild: Type.Recursive((This) =>
        Type.Object({
          name: Type.String(),
          big: Type.BigInt(),
          embedded: Type.Object({hello: Type.String(), child: Type.Optional(This)}),
        })
      ),
    })
  )
